    $('#reset').click(function(){
        // Destroy existing polygons on map
        for (var i=0; i<myAreaPolygon.length; i++) {
            myAreaPolygon[i].setMap(null);
        }
        // Destroy myAreaPolygon array of polygon objects
        myAreaPolygon = [];
