            $rel = array_key_exists(
                $mod,
                $this->field_defs
            ) ? $mod : $mod . "_activities_emails"; //Custom modules rel name
            if ($this->load_relationship($rel)) {
                $this->$rel->add($this->parent_id);
            }
        }
    }
    $GLOBALS['log']->debug('-------------------------------> Email save() done');

    return $id;
}

