		} catch (exception $e) {
			$this->seek($s);
			$this->throwError($e->getMessage());
		}

		$hidden = false;
		if (is_null($block->type)) {
			$hidden = true;
			if (!isset($block->args)) {
				foreach ($block->tags as $tag) {
					if (!is_string($tag) || $tag{0} != $this->lessc->mPrefix) {
						$hidden = false;
						break;
					}
				}
			}

			foreach ($block->tags as $tag) {
				if (is_string($tag)) {
					$this->env->children[$tag][] = $block;
				}
			}
		}

		if (!$hidden) {
			$this->append(array('block', $block), $s);
		}

